    nock('http://example.com')
      .get('/test.png')
      .reply(200, imageContent, { 'Content-Type': 'image/png' });

    const indexDir = path.dirname(require.resolve('../../../../../../../../../../../subject_repositories/image-downloader/index.js'));
    const relativeDest = path.relative(indexDir, tmpDir);

    const result = await image({
